import{_ as t,o as a,c as r,a2 as o}from"./chunks/framework.BKG_UbFK.js";const p=JSON.parse('{"title":"Введение","description":"","frontmatter":{},"headers":[],"relativePath":"ru/guide/introduction.md","filePath":"ru/guide/introduction.md"}'),d={name:"ru/guide/introduction.md"};function i(l,e,c,n,s,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="введение" tabindex="-1">Введение <a class="header-anchor" href="#введение" aria-label="Permalink to &quot;Введение&quot;">​</a></h1><h2 id="что-такое-clearance" tabindex="-1">Что такое Clearance? <a class="header-anchor" href="#что-такое-clearance" aria-label="Permalink to &quot;Что такое Clearance?&quot;">​</a></h2><p>Clearance - это готовая к использованию панель администратора для приложений Laravel, построенная поверх <a href="https://github.com/spatie/laravel-permission" target="_blank" rel="noreferrer">spatie/laravel-permission</a>. Она добавляет панель на Livewire 4 + Flux UI для управления разрешениями, ролями, guard&#39;ами и настройками, а также слой контекстной авторизации и потолки (ceiling) для ролей - устанавливается одной командой artisan, без изменения каких-либо таблиц Spatie.</p><p>Clearance даёт вам:</p><ul><li><strong>Панель администратора</strong> для Разрешений, Ролей, Guards, Настроек и Дашборда - используйте готовые маршруты или встраивайте каждый Livewire-компонент по отдельности.</li><li><strong>Контекстная авторизация</strong> - выдавайте роль или разрешение в привязке к конкретному экземпляру модели (Store, Tenant, Project) с помощью <code>$user-&gt;canIn()</code>, директив Blade <code>@canin</code>/<code>@hasrolein</code> и <code>ContextService</code> для использования вне модели User.</li><li><strong>Ceiling-роли</strong> - роль может объявить родительскую роль, чьё множество разрешений выступает верхней границей; дочерняя роль никогда не может превысить родительскую - это обеспечивается автоматически при каждом сохранении.</li><li><strong>Точечные права на запись</strong> - одно делегируемое разрешение <code>clearance-{section}-write</code> на каждый раздел панели, так что вы можете выдать &quot;управление ролями&quot;, не выдавая заодно &quot;управление настройками&quot;.</li><li><strong>Super Admin</strong> с опциональным глобальным обходом Gate, обнаружением алиасов для уже существующих admin-подобных ролей и безопасным неразрушающим повышением роли.</li><li><strong>Модуль пользователей</strong> (опционально) - назначайте роли глобально или в конкретном контексте, плюс переопределения разрешений по контексту, из панели для отдельного пользователя.</li><li><strong>Панель настроек</strong> - отображаемое имя, описание, санитизированная SVG-иконка и цвет для каждой роли/guard&#39;а; настраиваемая роль по умолчанию с авто-назначением и массовым назначением.</li><li><strong>Управление Guards</strong> - guard&#39;ы, хранящиеся в базе данных, внедряются в <code>auth.guards</code> при загрузке приложения, ограничены allow-list&#39;ом драйверов.</li><li><strong>9 языков в комплекте</strong> (ar, en, es, fr, hi, it, pt, ru, zh), паритет ключей проверяется тестами.</li><li><strong>Точки расширения</strong> - трейт <code>HasClearance</code>, трейт <code>HasPermissionGroups</code>, контракт <code>ClearanceContextable</code>, переиспользуемые компоненты Blade.</li><li><strong>Санитизация SVG</strong> - каждая иконка, загруженная пользователем, проходит через санитайзер на основе allow-list перед сохранением и при рендеринге.</li><li><strong>Защищено с точки зрения безопасности</strong> - ограничения (ceiling) против повышения привилегий на каждом пути выдачи разрешений, приоритет запрета в контекстных переопределениях, защищённое пространство имён <code>clearance-*</code>. См. <a href="/clearance-docs/ru/guide/security.html">Безопасность</a>.</li></ul><h2 id="связь-с-spatie-laravel-permission" tabindex="-1">Связь с spatie/laravel-permission <a class="header-anchor" href="#связь-с-spatie-laravel-permission" aria-label="Permalink to &quot;Связь с spatie/laravel-permission&quot;">​</a></h2><p>Clearance - это не замена пакета разрешений Spatie, а слой UI и авторизации поверх него. Роли и разрешения остаются моделями <code>Role</code> и <code>Permission</code> из Spatie и по-прежнему хранятся в таблицах Spatie <code>roles</code>, <code>permissions</code>, <code>model_has_roles</code>, <code>model_has_permissions</code> и <code>role_has_permissions</code>. Clearance никогда не изменяет эти таблицы. Всё, что Clearance добавляет - метаданные отображения, область роли, ceiling, контекстные назначения, переопределения по контексту - хранится в собственном наборе таблиц <code>clr_*</code>. См. <a href="/clearance-docs/ru/guide/architecture.html">Архитектуру</a> для полного разбора.</p><h2 id="требования" tabindex="-1">Требования <a class="header-anchor" href="#требования" aria-label="Permalink to &quot;Требования&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Зависимость</th><th>Версия</th></tr></thead><tbody><tr><td>PHP</td><td>^8.3</td></tr><tr><td>Laravel</td><td>^11.0 | ^12.0 | ^13.0</td></tr><tr><td>spatie/laravel-permission</td><td>^6.0</td></tr><tr><td>livewire/livewire</td><td>^3.0 | ^4.0</td></tr><tr><td>livewire/flux</td><td>^2.14</td></tr></tbody></table><h2 id="ключевые-понятия" tabindex="-1">Ключевые понятия <a class="header-anchor" href="#ключевые-понятия" aria-label="Permalink to &quot;Ключевые понятия&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Понятие</th><th>Описание</th></tr></thead><tbody><tr><td>Permission (разрешение)</td><td>Разрешение Spatie, следующее соглашению об именовании <code>group-action</code> (напр. <code>orders-create</code>). Предоставляет способность (ability).</td></tr><tr><td>Область роли (role scope)</td><td>Каждая роль либо <code>global</code> (назначается напрямую, применяется везде), либо <code>contextual</code> (привязана к конкретным типам моделей, назначается только в рамках экземпляра контекста).</td></tr><tr><td>Ceiling-роль</td><td>Роль может объявить родительскую роль, чьё множество разрешений является верхней границей - дочерняя роль никогда не может её превысить.</td></tr><tr><td>Контекст</td><td>Экземпляр модели (Store, Tenant, Project), к которому может быть привязана роль или переопределение разрешения.</td></tr><tr><td>Переопределение (override)</td><td>Персональное, привязанное к контексту разрешение или запрет <code>forced_on</code>/<code>forced_off</code> - запрет всегда побеждает.</td></tr></tbody></table><p>Для каждого из этих понятий есть отдельная страница: <a href="/clearance-docs/ru/features/permissions.html">Разрешения</a>, <a href="/clearance-docs/ru/features/roles.html">Роли</a>, <a href="/clearance-docs/ru/features/contextual-authorization.html">Контекстная авторизация</a>, <a href="/clearance-docs/ru/features/users.html">Пользователи</a>, <a href="/clearance-docs/ru/features/super-admin.html">Super Admin</a>.</p><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><p>Готовы установить Clearance? Переходите к <a href="/clearance-docs/ru/guide/installation.html">руководству по установке</a>.</p>',14)])])}const g=t(d,[["render",i]]);export{p as __pageData,g as default};
